-- Additive shared reporting schema. Definitions are metadata only; data execution remains server-side.
insert into public.permissions(key,name_ar,name_en) values ('reports.view','عرض التقارير','View reports'),('reports.create','إنشاء التقارير','Create reports'),('reports.edit','تعديل التقارير','Edit reports'),('reports.publish','نشر التقارير','Publish reports'),('reports.export','تصدير التقارير','Export reports'),('reports.schedule','جدولة التقارير','Schedule reports'),('dashboards.view','عرض اللوحات','View dashboards'),('dashboards.manage','إدارة اللوحات','Manage dashboards') on conflict(key) do nothing;
insert into public.role_permissions(role_id,permission_id) select r.id,p.id from public.roles r join public.permissions p on p.key in ('reports.view','reports.create','reports.edit','reports.publish','reports.export','reports.schedule','dashboards.view','dashboards.manage') where r.key='platform_owner' on conflict do nothing;
create table public.report_definitions(id uuid primary key default gen_random_uuid(),tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),module_key text not null,name_ar text,name_en text not null,description_ar text,description_en text,status public.workflow_version_status not null default 'draft',current_version_id uuid,owner_id uuid not null references public.user_profiles(id),created_at timestamptz not null default now(),created_by uuid references public.user_profiles(id),updated_at timestamptz not null default now(),updated_by uuid references public.user_profiles(id),archived_at timestamptz,archived_by uuid references public.user_profiles(id));
create table public.report_versions(id uuid primary key default gen_random_uuid(),definition_id uuid not null references public.report_definitions(id) on delete restrict,tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),version integer not null,status public.workflow_version_status not null default 'draft',definition jsonb not null default '{}'::jsonb,created_at timestamptz not null default now(),created_by uuid references public.user_profiles(id),updated_at timestamptz not null default now(),updated_by uuid references public.user_profiles(id),unique(definition_id,version));
alter table public.report_definitions add constraint report_current_version_fk foreign key(current_version_id) references public.report_versions(id) deferrable initially deferred;
create table public.dashboard_definitions(id uuid primary key default gen_random_uuid(),tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),module_key text,name_ar text,name_en text not null,status public.workflow_version_status not null default 'draft',owner_id uuid not null references public.user_profiles(id),created_at timestamptz not null default now(),created_by uuid references public.user_profiles(id),updated_at timestamptz not null default now(),updated_by uuid references public.user_profiles(id));
create table public.dashboard_widgets(id uuid primary key default gen_random_uuid(),dashboard_id uuid not null references public.dashboard_definitions(id) on delete restrict,tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),widget_type text not null check(widget_type in ('kpi_card','counter','gauge','line','area','bar','stacked_bar','pie','donut','heatmap','trend','table','top_n','timeline','activity_feed')),title_ar text,title_en text,report_version_id uuid references public.report_versions(id),configuration jsonb not null default '{}'::jsonb,display_order integer not null check(display_order>=0),created_at timestamptz not null default now(),created_by uuid references public.user_profiles(id),unique(dashboard_id,display_order));
create table public.saved_reports(id uuid primary key default gen_random_uuid(),tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),report_version_id uuid not null references public.report_versions(id) on delete restrict,name text not null,filters jsonb not null default '[]'::jsonb,owner_id uuid not null references public.user_profiles(id),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.report_runs(id uuid primary key default gen_random_uuid(),tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),report_version_id uuid not null references public.report_versions(id) on delete restrict,filters jsonb not null default '[]'::jsonb,status text not null default 'requested' check(status in ('requested','running','completed','failed')),requested_by uuid not null references public.user_profiles(id),started_at timestamptz,completed_at timestamptz,error_code text,created_at timestamptz not null default now());
create table public.report_exports(id uuid primary key default gen_random_uuid(),tenant_id uuid not null references public.tenants(id),organization_id uuid not null references public.organizations(id),facility_id uuid references public.facilities(id),report_run_id uuid references public.report_runs(id) on delete restrict,format text not null check(format in ('pdf','excel','csv')),language text not null check(language in ('ar','en','bilingual')),status text not null default 'requested' check(status in ('requested','ready','failed','expired')),storage_key text,requested_by uuid not null references public.user_profiles(id),created_at timestamptz not null default now(),expires_at timestamptz);
create or replace function public.can_report(p_permission text,p_tenant uuid,p_organization uuid,p_facility uuid) returns boolean language sql stable security definer set search_path=public as $$ select auth.uid() is not null and public.scope_allowed(p_tenant,p_organization,p_facility) and (public.has_platform_permission(p_permission,p_tenant,p_organization,p_facility) or public.has_platform_permission('platform.full_access',p_tenant,p_organization,p_facility)); $$;
create or replace function public.enforce_report_scope() returns trigger language plpgsql security definer set search_path=public as $$ begin if tg_table_name='report_versions' and not exists(select 1 from public.report_definitions d where d.id=new.definition_id and d.tenant_id=new.tenant_id and d.organization_id=new.organization_id and d.facility_id is not distinct from new.facility_id) then raise exception 'Report version scope mismatch' using errcode='23503'; end if; if tg_table_name='dashboard_widgets' and not exists(select 1 from public.dashboard_definitions d where d.id=new.dashboard_id and d.tenant_id=new.tenant_id and d.organization_id=new.organization_id and d.facility_id is not distinct from new.facility_id) then raise exception 'Dashboard widget scope mismatch' using errcode='23503'; end if; return new; end $$;
create or replace function public.prevent_published_report_mutation() returns trigger language plpgsql security definer set search_path=public as $$ begin if old.status='published' then raise exception 'Published report versions are immutable'; end if; return new; end $$;
create trigger report_versions_scope before insert or update on public.report_versions for each row execute function public.enforce_report_scope(); create trigger dashboard_widgets_scope before insert or update on public.dashboard_widgets for each row execute function public.enforce_report_scope(); create trigger report_versions_immutable before update or delete on public.report_versions for each row execute function public.prevent_published_report_mutation();
alter table public.report_definitions enable row level security; alter table public.report_versions enable row level security; alter table public.dashboard_definitions enable row level security; alter table public.dashboard_widgets enable row level security; alter table public.saved_reports enable row level security; alter table public.report_runs enable row level security; alter table public.report_exports enable row level security;
create policy report_definitions_read on public.report_definitions for select using(public.can_report('reports.view',tenant_id,organization_id,facility_id)); create policy report_versions_read on public.report_versions for select using(public.can_report('reports.view',tenant_id,organization_id,facility_id) and status='published'); create policy dashboards_read on public.dashboard_definitions for select using(public.can_report('dashboards.view',tenant_id,organization_id,facility_id)); create policy dashboard_widgets_read on public.dashboard_widgets for select using(public.can_report('dashboards.view',tenant_id,organization_id,facility_id)); create policy saved_reports_owner on public.saved_reports for all using(owner_id=auth.uid() and public.can_report('reports.view',tenant_id,organization_id,facility_id)) with check(owner_id=auth.uid() and public.can_report('reports.view',tenant_id,organization_id,facility_id)); create policy report_runs_owner on public.report_runs for select using(requested_by=auth.uid() and public.can_report('reports.view',tenant_id,organization_id,facility_id)); create policy report_exports_owner on public.report_exports for select using(requested_by=auth.uid() and public.can_report('reports.export',tenant_id,organization_id,facility_id));
revoke all on function public.can_report(text,uuid,uuid,uuid) from public,anon; grant execute on function public.can_report(text,uuid,uuid,uuid) to authenticated; revoke all on function public.enforce_report_scope(),public.prevent_published_report_mutation() from public,anon,authenticated;
create or replace function public.publish_report_version(p_definition_id uuid,p_version_id uuid) returns void language plpgsql security definer set search_path=public as $$ declare d public.report_definitions%rowtype; v public.report_versions%rowtype; begin select * into d from public.report_definitions where id=p_definition_id for update; select * into v from public.report_versions where id=p_version_id for update; if not found or v.definition_id<>d.id or v.status<>'approved' or not public.can_report('reports.publish',d.tenant_id,d.organization_id,d.facility_id) then raise exception 'Report publication denied'; end if; update public.report_versions set status='published',updated_at=now(),updated_by=auth.uid() where id=v.id; update public.report_definitions set status='published',current_version_id=v.id,updated_at=now(),updated_by=auth.uid() where id=d.id; end $$;
revoke all on function public.publish_report_version(uuid,uuid) from public,anon; grant execute on function public.publish_report_version(uuid,uuid) to authenticated;
